#include<bits/stdc++.h>
using namespace std;
long long f[12][12][12][39];
long long l1,l2,l3,d;
const long long mod=11380;
int main()
{
    scanf("%lld%lld%lld%lld",&l1,&l2,&l3,&d);
    for(long long i=0;i<=d;i++)
    {
        f[0][0][0][i]=1;
    }
    for(long long l=1;l<=d;l++)
    {
        for(long long i=0;i<=l1;i++)
        {
            for(long long j=0;j<=l2;j++)
            {
                for(long long k=0;k<=l3;k++)
                {
                    if(i==0&&j==0&&k==0)
                    {
                        continue;
                    }
                    for(long long a=0;a<i;a++)
                    {
                        for(long long b=0;b<=j;b++)
                        {
                            for(long long c=0;c<=k;c++)
                            {
                                f[i][j][k][l]=(f[i][j][k][l]+1ll*f[i-a-1][j-b][k-c][l]*f[a][b][c][l-1])%mod;
                            }
                        }
                    }
                    for(long long a=0;a<j;a++)
                    {
                        for(long long b=0;b<=k;b++)
                        {
                            f[i][j][k][l]=(f[i][j][k][l]+1ll*f[i][j-a-1][k-b][l]*f[0][a][b][l-1])%mod;
                        }
                    }
                    for(long long a=0;a<k;a++)
                    {
                        f[i][j][k][l]=(f[i][j][k][l]+1ll*f[i][j][k-a-1][l]*f[0][0][a][l-1])%mod;
                    }
                }
            }
        }
    }
    if(d==0)
    {
        if(l1==0&&l2==0&&l3==0)
        {
            printf("1");
        }
        else
        {
            printf("0");
        }
    }
    else if(l1==0&&l2==0&&l3==0)
    {
        printf("0");
    }
    else
    {
        printf("%lld",((f[l1][l2][l3][d]-f[l1][l2][l3][d-1])%mod+mod)%mod);
    }
    return 0;
}
